-- ============================================
-- 🎬 INTRO
-- ============================================
local function PlayIntro(callback)
    local introFrame = Instance.new("Frame")
    introFrame.Size = UDim2.new(1, 0, 1, 0)
    introFrame.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
    introFrame.BackgroundTransparency = 0
    introFrame.ZIndex = 1000
    introFrame.Parent = UI.Gui
    
    local vknLogo = Instance.new("TextLabel")
    vknLogo.Size = UDim2.new(1, 0, 0, 80)
    vknLogo.Position = UDim2.new(0, 0, 0.35, -40)
    vknLogo.BackgroundTransparency = 1
    vknLogo.Text = "VKN"
    vknLogo.TextColor3 = Config.Colors.BloodRed
    vknLogo.TextSize = 60
    vknLogo.Font = Enum.Font.GothamBold
    vknLogo.TextXAlignment = Enum.TextXAlignment.Center
    vknLogo.ZIndex = 1001
    vknLogo.Parent = introFrame
    
    local subText = Instance.new("TextLabel")
    subText.Size = UDim2.new(1, 0, 0, 30)
    subText.Position = UDim2.new(0, 0, 0.5, -15)
    subText.BackgroundTransparency = 1
    subText.Text = "KEY SYSTEM"
    subText.TextColor3 = Config.Colors.TextDim
    subText.TextSize = 18
    subText.Font = Enum.Font.Gotham
    subText.TextXAlignment = Enum.TextXAlignment.Center
    subText.ZIndex = 1001
    subText.Parent = introFrame
    
    local loadingBar = Instance.new("Frame")
    loadingBar.Size = UDim2.new(0, 350, 0, 6)
    loadingBar.Position = UDim2.new(0.5, -175, 0.7, 0)
    loadingBar.BackgroundColor3 = Config.Colors.Charcoal
    loadingBar.BorderSizePixel = 0
    loadingBar.ZIndex = 1001
    loadingBar.Parent = introFrame
    
    local barCorner = Instance.new("UICorner")
    barCorner.CornerRadius = UDim.new(0, 3)
    barCorner.Parent = loadingBar
    
    local progress = Instance.new("Frame")
    progress.Size = UDim2.new(0, 0, 1, 0)
    progress.BackgroundColor3 = Config.Colors.BloodRed
    progress.BorderSizePixel = 0
    progress.Parent = loadingBar
    
    local progressCorner = Instance.new("UICorner")
    progressCorner.CornerRadius = UDim.new(0, 3)
    progressCorner.Parent = progress
    
    for i = 1, 40 do
        local particle = Instance.new("Frame")
        particle.Size = UDim2.new(0, math.random(2, 6), 0, math.random(2, 6))
        particle.Position = UDim2.new(math.random(), 0, math.random(), 0)
        particle.BackgroundColor3 = Config.Colors.BloodRed
        particle.BackgroundTransparency = math.random(30, 70) / 100
        particle.BorderSizePixel = 0
        particle.ZIndex = 1002
        particle.Parent = introFrame
        
        local corner = Instance.new("UICorner")
        corner.CornerRadius = UDim.new(1, 0)
        corner.Parent = particle
        
        task.spawn(function()
            local xDir = (math.random() - 0.5) * 0.02
            local yDir = (math.random() - 0.5) * 0.02
            while introFrame and introFrame.Parent do
                local newX = particle.Position.X.Scale + xDir
                local newY = particle.Position.Y.Scale + yDir
                if newX > 1 or newX < 0 then xDir = -xDir end
                if newY > 1 or newY < 0 then yDir = -yDir end
                particle.Position = UDim2.new(math.clamp(newX, 0, 1), 0, math.clamp(newY, 0, 1), 0)
                particle.Rotation = particle.Rotation + (math.random() - 0.5) * 10
                task.wait(0.05)
            end
        end)
    end
    
    local width = 0
    while width < 350 do
        width = width + math.random(10, 20)
        progress:TweenSize(UDim2.new(0, math.min(width, 350), 1, 0), "Out", "Linear", 0.08)
        progress.BackgroundColor3 = width % 50 < 25 and Config.Colors.BloodRed or Config.Colors.FireOrange
        task.wait(0.08)
    end
    
    local flash = Instance.new("Frame")
    flash.Size = UDim2.new(1, 0, 1, 0)
    flash.BackgroundColor3 = Config.Colors.BloodRed
    flash.BackgroundTransparency = 0.5
    flash.ZIndex = 1003
    flash.Parent = introFrame
    TweenService:Create(flash, TweenInfo.new(0.3), {BackgroundTransparency = 1}):Play()
    
    TweenService:Create(vknLogo, TweenInfo.new(0.3), {TextTransparency = 1}):Play()
    TweenService:Create(subText, TweenInfo.new(0.3), {TextTransparency = 1}):Play()
    TweenService:Create(loadingBar, TweenInfo.new(0.3), {BackgroundTransparency = 1}):Play()
    
    task.wait(0.4)
    introFrame:Destroy()
    
    if callback then callback() end
end

-- ============================================
-- 🎨 FUNCIÓN PARA BORDES EN ÁNGULO
-- ============================================
local function CreateAngledCorner(parent, position, size, color, rotation)
    local cornerPiece = Instance.new("Frame")
    cornerPiece.Size = UDim2.new(0, size, 0, size)
    cornerPiece.Position = position
    cornerPiece.BackgroundColor3 = color
    cornerPiece.BorderSizePixel = 0
    cornerPiece.Rotation = rotation or 0
    cornerPiece.ZIndex = 110
    cornerPiece.Parent = parent
    
    local cornerCorner = Instance.new("UICorner")
    cornerCorner.CornerRadius = UDim.new(0, 2)
    cornerCorner.Parent = cornerPiece
    
    return cornerPiece
end

-- ============================================
-- 🖼️ CONTENEDOR PRINCIPAL
-- ============================================
local function CreateContainer()
    local container = Instance.new("Frame")
    container.Size = UDim2.new(0, 420, 0, 500)
    container.Position = UDim2.new(0.5, -210, 0.5, -250)
    container.BackgroundColor3 = Config.Colors.BlackMetal
    container.BorderSizePixel = 0
    container.ClipsDescendants = true
    container.Visible = false
    container.Parent = UI.Gui
    
    local mainBorder = Instance.new("Frame")
    mainBorder.Size = UDim2.new(1, 0, 1, 0)
    mainBorder.Position = UDim2.new(0, 0, 0, 0)
    mainBorder.BackgroundTransparency = 1
    mainBorder.ZIndex = 108
    mainBorder.Parent = container
    
    local borderStroke = Instance.new("UIStroke")
    borderStroke.Color = Config.Colors.BloodRed
    borderStroke.Thickness = 2.5
    borderStroke.Transparency = 0.2
    borderStroke.Parent = mainBorder
    
    local borderCorner = Instance.new("UICorner")
    borderCorner.CornerRadius = UDim.new(0, 16)
    borderCorner.Parent = mainBorder
    
    local spikeSize = 18
    local spikeColor = Config.Colors.BloodRed
    
    CreateAngledCorner(container, UDim2.new(0, -8, 0, -8), spikeSize, spikeColor, 0)
    CreateAngledCorner(container, UDim2.new(1, -10, 0, -8), spikeSize, spikeColor, 90)
    CreateAngledCorner(container, UDim2.new(0, -8, 1, -10), spikeSize, spikeColor, -90)
    CreateAngledCorner(container, UDim2.new(1, -10, 1, -10), spikeSize, spikeColor, 180)
    
    local topEdge = Instance.new("Frame")
    topEdge.Size = UDim2.new(0.8, 0, 0, 3)
    topEdge.Position = UDim2.new(0.1, 0, 0, -5)
    topEdge.BackgroundColor3 = Config.Colors.DarkRed
    topEdge.BorderSizePixel = 0
    topEdge.Parent = container
    
    local bottomEdge = Instance.new("Frame")
    bottomEdge.Size = UDim2.new(0.8, 0, 0, 3)
    bottomEdge.Position = UDim2.new(0.1, 0, 1, 2)
    bottomEdge.BackgroundColor3 = Config.Colors.DarkRed
    bottomEdge.BorderSizePixel = 0
    bottomEdge.Parent = container
    
    UI.Container = container
    return container
end

-- ============================================
-- 👑 HEADER
-- ============================================
local function CreateHeader(parent)
    local header = Instance.new("Frame")
    header.Size = UDim2.new(1, 0, 0, 120)
    header.BackgroundTransparency = 1
    header.Parent = parent
    
    local iconContainer = Instance.new("Frame")
    iconContainer.Size = UDim2.new(0, 75, 0, 75)
    iconContainer.Position = UDim2.new(0.5, -37.5, 0, 15)
    iconContainer.BackgroundColor3 = Config.Colors.Charcoal
    iconContainer.BorderSizePixel = 0
    iconContainer.Parent = header
    
    local iconCorner = Instance.new("UICorner")
    iconCorner.CornerRadius = UDim.new(0, 15)
    iconCorner.Parent = iconContainer
    
    local iconBorder = Instance.new("UIStroke")
    iconBorder.Color = Config.Colors.BloodRed
    iconBorder.Thickness = 2
    iconBorder.Transparency = 0.3
