local function SpawnBloodParticle()
    if not UI.Particles then return end
    
    local size = math.random(3, 10)
    local particle = Instance.new("Frame")
    particle.Size = UDim2.new(0, size, 0, size)
    particle.Position = UDim2.new(math.random(), 0, 1.1, 0)
    particle.BackgroundColor3 = math.random() < 0.7 and Config.Colors.BloodRed or Config.Colors.DarkRed
    particle.BackgroundTransparency = math.random(30, 60) / 100
    particle.BorderSizePixel = 0
    particle.Parent = UI.Particles
    
    local corner = Instance.new("UICorner")
    corner.CornerRadius = UDim.new(1, 0)
    corner.Parent = particle
    
    local data = {
        frame = particle,
        vx = (math.random() - 0.5) * 0.015,
        vy = -math.random(4, 10) / 100,
        rotation = 0,
        rotSpeed = (math.random() - 0.5) * 12,
        life = 0,
        maxLife = math.random(30, 70)
    }
    
    table.insert(State.Particles, data)
    return particle
end

local function UpdateParticles()
    for i = #State.Particles, 1, -1 do
        local p = State.Particles[i]
        if not p.frame or not p.frame.Parent then
            table.remove(State.Particles, i)
        else
            p.life = p.life + 1
            if p.life > p.maxLife or p.frame.Position.Y.Scale < -0.2 then
                p.frame:Destroy()
                table.remove(State.Particles, i)
            else
                local newX = p.frame.Position.X.Scale + p.vx
                local newY = p.frame.Position.Y.Scale + p.vy
                p.rotation = p.rotation + p.rotSpeed
                p.frame.Rotation = p.rotation
                p.frame.Position = UDim2.new(newX, 0, newY, 0)
                p.frame.BackgroundTransparency = p.frame.BackgroundTransparency + 0.005
            end
        end
    end
    
    if #State.Particles < 25 and math.random() < 0.35 then
        SpawnBloodParticle()
    end
end

