-- ============================================
-- 📝 ESTADOS
-- ============================================
local function SetStatus(text, color)
    if UI.Status then
        UI.Status.Text.Text = text
        UI.Status.Text.TextColor3 = color
        UI.Status.LED.BackgroundColor3 = color
        UI.Status.Text.TextTransparency = 1
        TweenService:Create(UI.Status.Text, TweenInfo.new(0.15), {TextTransparency = 0}):Play()
    end
end

local function SetLoading(loading)
    State.Loading = loading
    if loading then
        UI.MainButton.Button.Text = ""
        UI.MainButton.Spinner.Visible = true
        local tween = TweenService:Create(UI.MainButton.SpinnerCircle, 
            TweenInfo.new(0.5, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut, -1), 
            {Rotation = 360})
        tween:Play()
        UI.MainButton.SpinnerTween = tween
    else
        UI.MainButton.Button.Text = Config.Texts.ButtonVerify
        UI.MainButton.Spinner.Visible = false
        if UI.MainButton.SpinnerTween then
            UI.MainButton.SpinnerTween:Cancel()
            UI.MainButton.SpinnerCircle.Rotation = 0
        end
    end
end

-- ============================================
-- 🎮 EVENTOS PRINCIPALES
-- ============================================
local function SetupEvents()
    UserInputService.InputBegan:Connect(function(input)
        if input.KeyCode == Enum.KeyCode.Return and UI.Input.TextBox:IsFocused() and not State.Loading then
            local key = UI.Input.TextBox.Text
            if key == "" then
                SetStatus(Config.Texts.StatusError, Config.Colors.Error)
                ShakeContainer(8)
                return
            end
            
            SetLoading(true)
            SetStatus(Config.Texts.StatusLoading, Config.Colors.Warning)
            
            task.wait(0.8)
            
            if VerifyKey(key) then
                SetLoading(false)
                SetStatus(Config.Texts.StatusSuccess, Config.Colors.Success)
                print("[VKN] ✅ Clave correcta - Cargando UI principal...")
                
                task.wait(0.5)
                
                -- Cerrar Key System
                if UI.Gui then
                    UI.Gui:Destroy()
                end
                
                -- Cargar la UI principal
                LoadMainUI()
            else
                SetLoading(false)
                SetStatus(Config.Texts.StatusError, Config.Colors.Error)
                ShakeContainer(12)
                UI.Input.TextBox.Text = ""
                UI.Input.TextBox:CaptureFocus()
                task.wait(1.5)
                SetStatus(Config.Texts.StatusWaiting, Config.Colors.Warning)
            end
        end
    end)
    
    UI.MainButton.Button.MouseButton1Click:Connect(function()
        if State.Loading then return end
        
        local key = UI.Input.TextBox.Text
        if key == "" then
            SetStatus(Config.Texts.StatusError, Config.Colors.Error)
            ShakeContainer(8)
            return
        end
        
        SetLoading(true)
        SetStatus(Config.Texts.StatusLoading, Config.Colors.Warning)
        
        task.wait(0.8)
        
        if VerifyKey(key) then
            SetLoading(false)
            SetStatus(Config.Texts.StatusSuccess, Config.Colors.Success)
            print("[VKN] ✅ Clave correcta - Cargando UI principal...")
            
            task.wait(0.5)
            
            if UI.Gui then
                UI.Gui:Destroy()
            end
            
            LoadMainUI()
        else
            SetLoading(false)
            SetStatus(Config.Texts.StatusError, Config.Colors.Error)
            ShakeContainer(12)
            UI.Input.TextBox.Text = ""
            UI.Input.TextBox:CaptureFocus()
            task.wait(1.5)
            SetStatus(Config.Texts.StatusWaiting, Config.Colors.Warning)
        end
    end)
    
    UI.SecondaryButtons.GetKey.MouseButton1Click:Connect(function()
        local link = "https://your-keysite.com/getkey"
        if setclipboard then
            setclipboard(link)
            SetStatus(Config.Texts.StatusCopied, Config.Colors.Success)
            task.wait(1)
            SetStatus(Config.Texts.StatusWaiting, Config.Colors.Warning)
        end
    end)
    
    UI.SecondaryButtons.Discord.MouseButton1Click:Connect(function()
        if setclipboard then
            setclipboard(Config.DiscordLink)
            SetStatus(Config.Texts.StatusCopied, Config.Colors.Success)
            task.wait(1)
            SetStatus(Config.Texts.StatusWaiting, Config.Colors.Warning)
        end
    end)
end

-- ============================================
-- 🔄 LOOP
-- ============================================
local function StartParticleLoop()
    task.spawn(function()
        while UI.Gui and UI.Gui.Parent do
            pcall(UpdateParticles)
            task.wait(1/60)
        end
    end)
end

local function ShowMainUI()
    UI.Container.Visible = true
    UI.Container.BackgroundTransparency = 1
    UI.Container.Size = UDim2.new(0, 0, 0, 0)
    UI.Container.Position = UDim2.new(0.5, 0, 0.5, 0)
    
    TweenService:Create(UI.Container, TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out), 
        {Size = UDim2.new(0, 420, 0, 500), Position = UDim2.new(0.5, -210, 0.5, -250), BackgroundTransparency = 0}):Play()
    
    task.wait(0.4)
    UI.Input.TextBox:CaptureFocus()
end

