local function Initialize()
    print("[VKN] 🔥 Iniciando Key System...")
    
    local gui = Instance.new("ScreenGui")
    gui.Name = "VKNKeySystem"
    gui.ResetOnSpawn = false
    gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    gui.IgnoreGuiInset = true
    gui.Parent = PlayerGui
    UI.Gui = gui
    
    local backdrop = Instance.new("Frame")
    backdrop.Size = UDim2.new(1, 0, 1, 0)
    backdrop.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
    backdrop.BackgroundTransparency = 0.25
    backdrop.BorderSizePixel = 0
    backdrop.Parent = UI.Gui
    UI.Backdrop = backdrop
    
    CreateContainer()
    CreateHeader(UI.Container)
    CreateInputSection(UI.Container)
    CreateMainButton(UI.Container)
    CreateSecondaryButtons(UI.Container)
    CreateStatusBar(UI.Container)
    CreateParticles(UI.Gui)
    
    SetupEffects()
    SetupEvents()
    StartParticleLoop()
    
    PlayIntro(function()
        ShowMainUI()
    end)
end

